const staticData = $getWorkflowStaticData('global');
const hours = parseInt($input.first().json.query?.hours) || 12;
const seconds = hours * 3600;

staticData.customTimeWindow = seconds;

console.log(`Webhook trigger: searching last ${hours} hours (${seconds}s)`);

return [{json: {hours: hours, seconds: seconds, triggered: 'webhook'}}];

const staticData = $getWorkflowStaticData('global');
const msg = ($input.first().json.message?.text || '').trim();

// Parse commands like: /jobs 6, /jobs 12, /jobs
const match = msg.match(/^\/jobs(?:\s+(\d+))?$/);

if (!match) {
  // Not a valid command — ignore
  staticData.telegramTriggered = false;
  return [{json: {skip: true, reason: 'Invalid command. Use /jobs or /jobs <hours>'}}];
}

const hours = match[1] ? parseInt(match[1]) : 12; // Default 12 hours if no number given
const seconds = hours * 3600;

staticData.telegramTriggered = true;
staticData.customTimeWindow = seconds;
staticData.triggerChatId = $input.first().json.message?.chat?.id || '951213350';

console.log(`Telegram trigger: searching last ${hours} hours (${seconds}s)`);

return [{json: {hours: hours, seconds: seconds, triggered: true}}];

// Store config data in workflow static data for use by later nodes
const staticData = $getWorkflowStaticData('global');

// Store all config rows
staticData.config = $input.all().map(i => i.json);

// Initialize accumulators
staticData.newJobLinks = [];
staticData.existingJobIds = {};
staticData.processedJobs = [];

const activeCount = staticData.config.filter(c => 
  String(c.Active).toUpperCase() === 'TRUE' || c.Active === true
).length;

console.log(`Config loaded: ${staticData.config.length} companies, ${activeCount} active`);

return [{json: {configLoaded: true, totalCompanies: staticData.config.length, activeCompanies: activeCount}}];

// ============================================================
// SETTINGS — Change these before manual runs if needed
// ============================================================
const staticDataForTime = $getWorkflowStaticData('global');
const TIME_WINDOW_SECONDS = staticDataForTime.customTimeWindow || 86400;  // Default 24h, overridden by Telegram /jobs command
// Clear custom time after reading so scheduled runs use default
delete staticDataForTime.customTimeWindow;
const LOCATION = 'India';           // Search location
const GEO_ID = '102713980';         // India geoId
const LOCATION_FILTER = '105214831'; // Bengaluru, Karnataka f_PP filter
// ============================================================

const staticData = $getWorkflowStaticData('global');
const config = staticData.config || [];
const results = $input.all().map(i => i.json);

// Build dedup set from existing results
const existingJobIds = {};
for (const r of results) {
  if (r.JobID) existingJobIds[String(r.JobID)] = true;
}
staticData.existingJobIds = existingJobIds;
staticData.newJobLinks = [];

console.log(`Dedup set loaded: ${Object.keys(existingJobIds).length} existing job IDs`);

// Define keyword templates per bucket
const bucketKeywords = {
  '1': '"software development engineer" OR "SDE" OR "SDE II" OR "SDE 2" OR "SDE-II" OR "software engineer II" OR "software engineer 2" OR "software engineer - II"',
  '2': '"software engineer III" OR "software engineer 3" OR "software developer 3"',
  '3': '"software engineer" OR "software developer" OR "backend engineer" OR "SDE" OR "MTS" OR "member of technical staff"',
  '4': '"software engineer" OR "software developer" OR "backend engineer" OR "SDE" OR "MTS" OR "member of technical staff"'
};

// Group active companies by bucket
const buckets = {};
for (const item of config) {
  const isActive = String(item.Active).toUpperCase() === 'TRUE' || item.Active === true;
  if (!isActive) continue;

  const bucket = String(item.Bucket);
  if (!buckets[bucket]) buckets[bucket] = [];
  buckets[bucket].push(String(item.CompanyID));
}

// Build LinkedIn search URLs
const urls = [];
for (const [bucket, companyIds] of Object.entries(buckets)) {
  const keywords = bucketKeywords[bucket];
  if (!keywords || companyIds.length === 0) continue;

  const encodedKeywords = encodeURIComponent(keywords);
  const companyFilter = companyIds.join(',');
  const encodedLocation = encodeURIComponent(LOCATION);

  const url = `https://www.linkedin.com/jobs/search/?keywords=${encodedKeywords}&f_C=${companyFilter}&f_TPR=r${TIME_WINDOW_SECONDS}&location=${encodedLocation}&geoId=${GEO_ID}&f_PP=${LOCATION_FILTER}&sortBy=DD`;

  urls.push({
    url: url,
    bucket: bucket,
    companyCount: companyIds.length
  });
}

console.log(`Built ${urls.length} search URLs for ${Object.keys(buckets).length} active buckets`);

if (urls.length === 0) {
  return [{json: {url: '', bucket: '0', companyCount: 0, noUrls: true}}];
}

return urls.map(u => ({json: u}));

const staticData = $getWorkflowStaticData('global');
const existingIds = staticData.existingJobIds || {};
const newLinks = staticData.newJobLinks || [];

// Get current bucket from the URL item that flowed through
const currentBucket = $('Loop Over URLs').first().json.bucket || '0';

// Get extracted data
const data = $input.first().json;
const links = data.links || [];
const titles = data.titles || [];
const companies = data.companies || [];
const locations = data.locations || [];

// ============================================================
// NEGATIVE TITLE FILTER
// Titles containing these patterns are EXCLUDED
// ============================================================
// For Bucket 1 & 2: also exclude 'senior' and 'sr'
const negativeBase = /\b(staff|principal|lead|manager|director|ios|android|machine.?learning|data.?scien|QA|SDET|devops|SRE|site.?reliability|frontend|front.?end|intern|test.?engineer|test.?auto|platform.?engineer|infra.?engineer|cloud.?engineer|security|mobile|embedded)\b/i;
const negativeSenior = /\b(senior|sr\.?)\b/i;
// ============================================================

let filtered = 0;
let duped = 0;
let added = 0;

for (let i = 0; i < links.length; i++) {
  const url = links[i] || '';
  const title = (titles[i] || '').trim();
  const company = (companies[i] || '').trim();
  const location = (locations[i] || '').trim();

  // Extract job ID from URL (last numeric segment before '?' in slug like /view/title-JOBID?...)
  const match = url.match(/-(\d{8,})(?:\?|$)/);
  const jobId = match ? match[1] : null;

  if (!jobId) continue;

  // Dedup: check existing results AND already-found links
  if (existingIds[jobId]) { duped++; continue; }
  const alreadyFound = newLinks.some(l => l.jobId === jobId);
  if (alreadyFound) { duped++; continue; }

  // Apply negative title filter
  if (negativeBase.test(title)) { filtered++; continue; }

  // For Bucket 1 & 2, also exclude 'senior'
  if ((currentBucket === '1' || currentBucket === '2') && negativeSenior.test(title)) {
    filtered++; continue;
  }

  // Passed all filters! Add to accumulator
  newLinks.push({
    url: `https://www.linkedin.com/jobs/view/${jobId}`,
    jobId: jobId,
    bucket: currentBucket,
    searchTitle: title,
    searchCompany: company,
    searchLocation: location
  });
  added++;
}

staticData.newJobLinks = newLinks;

console.log(`Bucket ${currentBucket}: ${links.length} total, ${added} new, ${duped} dupes, ${filtered} filtered`);

return [{json: {processed: true, bucket: currentBucket, total: links.length, new: added, duped: duped, filtered: filtered}}];

const staticData = $getWorkflowStaticData('global');
const newLinks = staticData.newJobLinks || [];

console.log(`Total new job links to process: ${newLinks.length}`);

if (newLinks.length === 0) {
  // Return dummy item so the downstream loop still completes
  // and the notification chain runs (to catch unnotified from previous runs)
  return [{json: {dummy: true, jobId: 'none', url: '', message: 'No new jobs found this run'}}];
}

// Clear the accumulator
staticData.newJobLinks = [];

return newLinks.map(link => ({json: {...link, dummy: false}}));

// ============================================================
// SETTINGS
// ============================================================
const MAX_EXPERIENCE_YEARS = 4;  // Skip roles where minimum experience > 4 years
// ============================================================

const parsed = $input.first().json;

// Get original search data from the loop item
let searchData = {};
try {
  searchData = $('Loop Over Jobs').first().json || {};
} catch(e) {
  searchData = {};
}

const jobId = searchData.jobId || '';
const bucket = searchData.bucket || '';
const searchTitle = searchData.searchTitle || '';
const searchCompany = searchData.searchCompany || '';

// If parsing failed or dummy, mark as invalid
if (!parsed.title && !searchTitle) {
  return [{json: {valid: false, reason: 'parse_failed'}}];
}

const title = (parsed.title || searchTitle || '').trim();
const company = (parsed.company || searchCompany || '').trim();
const location = (parsed.location || searchData.searchLocation || '').trim();
const description = (parsed.description || '').replace(/\s+/g, ' ').trim();
const criteria = parsed.criteria || [];

// ============================================================
// EXPERIENCE EXTRACTION (regex-based, no LLM needed)
// ============================================================
let expText = 'Not specified';
let minExp = null;
let maxExp = null;

// Try extracting from description
const descLower = description.toLowerCase();

// Patterns: "3+ years", "3-5 years", "3 to 5 years", "minimum 3 years", "at least 3 years"
const expPatterns = [
  /(\d+)\s*\+\s*(?:years|yrs)/i,
  /(\d+)\s*[-–to]+\s*(\d+)\s*(?:years|yrs)/i,
  /(?:minimum|at least|min\.?)\s*(\d+)\s*(?:years|yrs)/i,
  /(\d+)\s*(?:years|yrs)\s*(?:of)?\s*(?:experience|exp)/i
];

for (const pattern of expPatterns) {
  const match = descLower.match(pattern);
  if (match) {
    minExp = parseInt(match[1]);
    maxExp = match[2] ? parseInt(match[2]) : null;
    expText = match[0].trim();
    break;
  }
}

// Also check criteria list (LinkedIn structured data)
for (const c of criteria) {
  const cLower = (c || '').toLowerCase().trim();
  // Sometimes criteria has "Mid-Senior level" or "Entry level"
  if (cLower.includes('entry')) {
    if (!minExp) { minExp = 0; expText = cLower; }
  } else if (cLower.includes('mid-senior')) {
    if (!minExp) { minExp = 3; expText = cLower; }
  }
}

// ============================================================
// FILTER: Skip if experience requirement > threshold
// ============================================================
const skipDueToExp = minExp !== null && minExp > MAX_EXPERIENCE_YEARS;

if (skipDueToExp) {
  console.log(`Skipping ${title} at ${company}: requires ${expText} (min ${minExp} yrs > ${MAX_EXPERIENCE_YEARS})`);
  return [{json: {valid: false, reason: 'experience_too_high', title, company, expText}}];
}

// ============================================================
// DETERMINE PRIMARY TAG
// ============================================================
let primaryTag = 'Generic';
const titleLower = title.toLowerCase();
if (/sde.?(?:ii|2)/i.test(titleLower)) primaryTag = 'SDE-II';
else if (/software.*engineer.*(?:iii|3)/i.test(titleLower)) primaryTag = 'SE-III';
else if (/mts|member.*technical/i.test(titleLower)) primaryTag = 'MTS';
else if (/senior|sr/i.test(titleLower)) primaryTag = 'Senior';
else if (/backend|back.?end/i.test(titleLower)) primaryTag = 'Backend';
else primaryTag = 'Generic';

// ============================================================
// ACCUMULATE FOR LLM MATCHING
// ============================================================
var expDisplay = 'Not specified';
if (minExp !== null && maxExp !== null) {
  expDisplay = minExp + '-' + maxExp + ' yrs';
} else if (minExp !== null) {
  expDisplay = minExp + '+ yrs';
}
var staticDataAcc = $getWorkflowStaticData('global');
if (!staticDataAcc.processedJobs) staticDataAcc.processedJobs = [];
staticDataAcc.processedJobs.push({
  jobId: jobId,
  title: title,
  company: company,
  location: location,
  link: 'https://www.linkedin.com/jobs/view/' + jobId,
  expDisplay: expDisplay,
  primaryTag: primaryTag,
  description: description.substring(0, 3000)
});

// ============================================================
// BUILD RESULT ROW
// ============================================================
const now = new Date().toISOString();

return [{json: {
  valid: true,
  JobID: jobId,
  Title: title,
  Company: company,
  Location: location,
  Link: 'https://www.linkedin.com/jobs/view/' + jobId,
  ExperienceReq: expText,
  PrimaryTag: primaryTag,
  FirstSeen: now,
  Notified: 'FALSE',
  Score: '',
  Status: 'New'
}}];

var staticData = $getWorkflowStaticData('global');
var items = $input.all();
var llmFailed = staticData.llmFailed === true;
var processedJobs = staticData.processedJobs || [];

// Filter to real job results
var jobs = items.filter(function(i) { return i.json.JobID && i.json.Title && i.json.Notified === false; });

if (jobs.length === 0) {
  return [{json: {hasJobs: false, message: 'No new jobs to notify', jobIds: [], scores: {}}}];
}

// Build score lookup from LLM results
var scoreMap = {};
if (!llmFailed && processedJobs.length > 0) {
  for (var p = 0; p < processedJobs.length; p++) {
    var pj = processedJobs[p];
    if (pj.jobId && pj.matchPercentage != null) {
      scoreMap[pj.jobId] = pj.matchPercentage;
    }
  }
}
var hasScores = !llmFailed && Object.keys(scoreMap).length > 0;

// Merge jobs with scores
var jobList = [];
for (var k = 0; k < jobs.length; k++) {
  var j = jobs[k].json;
  var score = scoreMap[String(j.JobID)];
  jobList.push({
    JobID: j.JobID,
    Title: j.Title,
    Company: j.Company,
    Location: j.Location,
    Link: j.Link,
    ExperienceReq: j.ExperienceReq,
    PrimaryTag: j.PrimaryTag,
    matchPercentage: typeof score === 'number' ? score : null
  });
}

// Sort by match % if scores available
if (hasScores) {
  jobList.sort(function(a, b) {
    var aP = a.matchPercentage != null ? a.matchPercentage : -1;
    var bP = b.matchPercentage != null ? b.matchPercentage : -1;
    return bP - aP;
  });
}

var MAX_LEN = 4000;
var messages = [];
var entries = [];

if (hasScores) {
  // ENRICHED format with match %
  var header = '\uD83D\uDD14 ' + jobList.length + ' New Opening' + (jobList.length > 1 ? 's' : '') + ' Found\n\n';
  for (var i = 0; i < jobList.length; i++) {
    var jb = jobList[i];
    var pct = jb.matchPercentage;
    var icon = '\uD83D\uDD34';
    if (typeof pct === 'number') {
      if (pct >= 70) icon = '\uD83D\uDFE2';
      else if (pct >= 50) icon = '\uD83D\uDFE1';
    }
    var pctStr = typeof pct === 'number' ? pct + '%' : 'N/A';
    var exp = jb.ExperienceReq && jb.ExperienceReq !== 'Not specified' ? ' (' + jb.ExperienceReq + ')' : '';
    var tag = jb.PrimaryTag ? ' [' + jb.PrimaryTag + ']' : '';
    var entry = (i+1) + '. ' + icon + ' ' + pctStr + ' \u2014 ' + jb.Company + ' \u2014 ' + jb.Title + exp + tag + '\n';
    entry += '   \uD83D\uDCCD ' + (jb.Location || 'N/A') + '\n';
    entry += '   \uD83D\uDD17 ' + jb.Link;
    entries.push(entry);
  }
  var current = header;
  for (var m = 0; m < entries.length; m++) {
    if (current.length + entries[m].length + 2 > MAX_LEN) {
      messages.push(current.trim());
      current = '...contd\n\n';
    }
    current += entries[m] + '\n\n';
  }
  if (current.trim()) messages.push(current.trim());
} else {
  // FALLBACK: plain format (no scores)
  var header2 = '\uD83D\uDD14 ' + jobList.length + ' New Opening' + (jobList.length > 1 ? 's' : '') + ' Found\n\n';
  for (var i2 = 0; i2 < jobList.length; i2++) {
    var jb2 = jobList[i2];
    var exp2 = jb2.ExperienceReq && jb2.ExperienceReq !== 'Not specified' ? ' (' + jb2.ExperienceReq + ')' : '';
    var tag2 = jb2.PrimaryTag ? ' [' + jb2.PrimaryTag + ']' : '';
    var entry2 = (i2+1) + '. ' + jb2.Company + ' \u2014 ' + jb2.Title + exp2 + tag2 + '\n';
    entry2 += '   \uD83D\uDCCD ' + (jb2.Location || 'N/A') + '\n';
    entry2 += '   ' + jb2.Link;
    entries.push(entry2);
  }
  var current2 = header2;
  for (var m2 = 0; m2 < entries.length; m2++) {
    if (current2.length + entries[m2].length + 2 > MAX_LEN) {
      messages.push(current2.trim());
      current2 = '...contd\n\n';
    }
    current2 += entries[m2] + '\n\n';
  }
  if (current2.trim()) messages.push(current2.trim());
  if (llmFailed && messages.length > 0) {
    messages[messages.length - 1] += '\n\n\u26A0\uFE0F AI matching unavailable this run.';
  }
}

// Build scores dict for downstream Score persistence
var scores = {};
for (var s = 0; s < jobList.length; s++) {
  if (jobList[s].matchPercentage != null) {
    scores[jobList[s].JobID] = jobList[s].matchPercentage;
  }
}

var jobIds = jobList.map(function(x) { return x.JobID; });

return [{json: {
  hasJobs: true,
  messages: messages,
  message: messages[0],
  jobIds: jobIds,
  count: jobList.length,
  scores: scores,
  llmFailed: llmFailed
}}];

const data = $input.first().json;
const messages = data.messages || [data.message];
const jobIds = data.jobIds || [];

return messages.map((msg, i) => ({
  json: {
    message: msg,
    jobIds: i === messages.length - 1 ? jobIds : []
  }
}));

// Get jobIds and scores from Format Telegram node (Send Telegram overwrites json with API response)
var allIds = [];
var scores = {};
try {
  var formatData = $('Format Telegram').first().json;
  allIds = formatData.jobIds || [];
  scores = formatData.scores || {};
} catch(e) {
  // Fallback: try from input
  var inputItems = $input.all();
  for (var i = 0; i < inputItems.length; i++) {
    var ids = inputItems[i].json.jobIds || [];
    for (var k = 0; k < ids.length; k++) { allIds.push(ids[k]); }
  }
}

if (allIds.length === 0) {
  return [{json: {nothing: true}}];
}

// Clean up staticData
var staticData = $getWorkflowStaticData('global');
delete staticData.processedJobs;
delete staticData.llmFailed;

return allIds.map(function(id) {
  var scoreVal = scores[id];
  return {
    json: {
      JobID: id,
      Notified: 'TRUE',
      Score: typeof scoreVal === 'number' ? String(scoreVal) : ''
    }
  };
});

var staticData = $getWorkflowStaticData('global');
var resumeRows = $input.all().map(function(i) { return i.json; });
var jobs = staticData.processedJobs || [];

// Build resume object from key-value rows
var resume = {};
for (var r = 0; r < resumeRows.length; r++) {
  var key = String(resumeRows[r].Key || '').trim();
  var value = String(resumeRows[r].Value || '').trim();
  if (key) resume[key] = value;
}

// Check if resume data is available
if (Object.keys(resume).length === 0 || !resume.name) {
  console.log('Resume tab is empty or missing — skipping LLM matching');
  staticData.llmFailed = true;
  return [{json: {llmRequired: false, reason: 'resume_empty'}}];
}

if (jobs.length === 0) {
  console.log('No jobs to match — skipping LLM');
  staticData.llmFailed = true;
  return [{json: {llmRequired: false, reason: 'no_jobs'}}];
}

// Build jobs array for LLM (truncate descriptions)
var jobsForLLM = jobs.map(function(j) {
  return {
    jobId: j.jobId,
    title: j.title,
    company: j.company,
    location: j.location,
    description: (j.description || '').substring(0, 3000),
    experienceReq: j.expDisplay,
    primaryTag: j.primaryTag
  };
});

var prompt = 'You are a job-resume matching assistant. Given a candidate\'s resume and a list of job postings, analyze how well the candidate matches each role.\n\n'
  + '## Candidate Resume\n' + JSON.stringify(resume, null, 2) + '\n\n'
  + '## Job Listings\n' + JSON.stringify(jobsForLLM, null, 2) + '\n\n'
  + '## Instructions\nFor each job in the jobs array:\n'
  + '1. Compare the job requirements against the candidate\'s resume\n'
  + '2. Calculate an honest match percentage based on: skills overlap (40%), experience level fit (30%), domain relevance (20%), and role seniority alignment (10%)\n'
  + '3. Write a one-line summary of what the role involves (max 100 characters)\n'
  + '4. List 2-4 key skills/experiences from the resume that match the job requirements\n'
  + '5. List 1-3 key skills/requirements the candidate is missing or weak on\n\n'
  + '## Scoring Guidelines\n'
  + '- 85-100%: Excellent match — skills, experience level, and domain align closely\n'
  + '- 70-84%: Strong match — most key requirements met, minor gaps\n'
  + '- 50-69%: Moderate match — relevant foundation but notable gaps\n'
  + '- 30-49%: Weak match — limited overlap, significant upskilling needed\n'
  + '- 0-29%: Poor match — fundamentally different domain or seniority\n\n'
  + '## Output Format\nReturn ONLY a valid JSON object. No markdown, no explanation, no text before or after.\n'
  + '{\n  "results": [\n    {\n      "jobId": "<same jobId from input>",\n      "matchPercentage": <integer 0-100>,\n      "summary": "<what the role does, max 100 chars>",\n      "keyMatches": ["<matching skill>", "<matching skill>"],\n      "keyGaps": ["<missing requirement>", "<missing requirement>"]\n    }\n  ]\n}\n\n'
  + 'RULES:\n'
  + '- Return results for ALL jobs in the input, in the same order\n'
  + '- Each jobId MUST match a jobId from the input exactly\n'
  + '- matchPercentage MUST be an integer between 0 and 100\n'
  + '- summary MUST be under 100 characters\n'
  + '- keyMatches: 2-4 items\n'
  + '- keyGaps: 1-3 items\n'
  + '- Do NOT fabricate skills the candidate doesn\'t have\n'
  + '- Do NOT add any text outside the JSON object';

console.log('Prepared LLM input: ' + jobs.length + ' jobs, resume keys: ' + Object.keys(resume).join(', '));

return [{json: {
  llmRequired: true,
  prompt: prompt,
  jobCount: jobs.length
}}];

var staticData = $getWorkflowStaticData('global');
var jobs = staticData.processedJobs || [];
var response = $input.first().json;

// Check if LLM was skipped
if (response.llmRequired === false) {
  console.log('LLM was skipped: ' + (response.reason || 'unknown'));
  staticData.llmFailed = true;
  return [{json: {llmFailed: true, reason: response.reason}}];
}

try {
  // Check for API error
  if (response.error || !response.candidates || !response.candidates[0]) {
    var errMsg = response.error ? response.error.message : 'No candidates in response';
    console.log('Gemini API error: ' + errMsg);
    staticData.llmFailed = true;
    return [{json: {llmFailed: true, reason: 'api_error', error: errMsg}}];
  }

  var text = '';
  try {
    text = response.candidates[0].content.parts[0].text || '';
  } catch(e) {
    text = '';
  }
  if (!text) {
    console.log('Empty response text from Gemini');
    staticData.llmFailed = true;
    return [{json: {llmFailed: true, reason: 'empty_response'}}];
  }

  // Parse JSON response
  var parsed = JSON.parse(text);
  var results = parsed.results || [];

  if (!Array.isArray(results) || results.length === 0) {
    console.log('No results array in LLM response');
    staticData.llmFailed = true;
    return [{json: {llmFailed: true, reason: 'no_results_array'}}];
  }

  // Build lookup by jobId
  var resultMap = {};
  for (var r = 0; r < results.length; r++) {
    if (results[r].jobId) resultMap[results[r].jobId] = results[r];
  }

  // Merge LLM results into processedJobs
  for (var j = 0; j < jobs.length; j++) {
    var match = resultMap[jobs[j].jobId];
    if (match) {
      jobs[j].matchPercentage = typeof match.matchPercentage === 'number' ?
        Math.max(0, Math.min(100, Math.round(match.matchPercentage))) : null;
      jobs[j].summary = (match.summary || '').substring(0, 100);
      jobs[j].keyMatches = Array.isArray(match.keyMatches) ? match.keyMatches.slice(0, 4) : [];
      jobs[j].keyGaps = Array.isArray(match.keyGaps) ? match.keyGaps.slice(0, 3) : [];
    } else {
      jobs[j].matchPercentage = null;
      jobs[j].summary = '';
      jobs[j].keyMatches = [];
      jobs[j].keyGaps = [];
    }
  }

  // Sort by matchPercentage descending (nulls at end)
  jobs.sort(function(a, b) {
    var aP = a.matchPercentage != null ? a.matchPercentage : -1;
    var bP = b.matchPercentage != null ? b.matchPercentage : -1;
    return bP - aP;
  });

  staticData.processedJobs = jobs;
  staticData.llmFailed = false;

  console.log('LLM matching complete: ' + results.length + ' results merged into ' + jobs.length + ' jobs');
  return [{json: {llmFailed: false, matchedCount: results.length, jobCount: jobs.length}}];

} catch (e) {
  console.log('LLM response parse error: ' + e.message);
  staticData.llmFailed = true;
  return [{json: {llmFailed: true, reason: 'parse_error', error: e.message}}];
}
